mapper.sql:
LEFT JOIN (
    SELECT session_id, COUNT(*) AS unread_count
    FROM chat_message
    WHERE is_read = 0 AND sender_id != #{userId}
    GROUP BY session_id
) uc ON cs.id = uc.session_id

mapper.select:
SELECT cs.task_application_id AS application_id, t.id AS task_id, t.title AS task_title, t.status AS task_status, ta.status AS application_status,
u.id AS counterpart_id, u.nickname AS counterpart_name, u.avatar_url AS counterpart_avatar
u.id AS counterpart_id, u.nickname AS counterpart_name, u.avatar_url AS counterpart_avatar
cs.last_message, cs.last_message_time, COALESCE(uc.unread_count, 0) AS unread_count FROM chat_session cs JOIN task_application ta ON cs.task_application_id = ta.id JOIN task t ON ta.task_id = t.id
JOIN enterprise e ON t.enterprise_id = e.id JOIN user u ON cs.seeker_id = u.id
JOIN user u ON cs.employer_id = u.id
WHERE cs.task_application_id = #{applicationId}
AND e.user_id = #{userId}
AND cs.seeker_id = #{userId}
